import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { base64ToUint8Array, createPcmBlob, decodeAudioData } from '../utils/audio-utils';
import { Message, VoiceName } from '../types';

interface UseGeminiLiveProps {
  voiceName: VoiceName;
}

export const useGeminiLive = ({ voiceName }: UseGeminiLiveProps) => {
  const [isConnected, setIsConnected] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [currentInput, setCurrentInput] = useState(''); // Real-time input transcription
  const [error, setError] = useState<string | null>(null);

  // Audio Contexts and Nodes
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputAnalyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Stream & Processor references
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Transcription buffers
  const currentInputTransRef = useRef('');
  const currentOutputTransRef = useRef('');

  const connect = useCallback(async () => {
    try {
      setError(null);
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
        throw new Error("API Key not found in environment variables");
      }

      // Initialize Audio Contexts
      const InputContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const OutputContextClass = window.AudioContext || (window as any).webkitAudioContext;

      const inputCtx = new InputContextClass({ sampleRate: 16000 });
      const outputCtx = new OutputContextClass({ sampleRate: 24000 });

      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;

      // Analysers for visualization
      const inputAnalyser = inputCtx.createAnalyser();
      inputAnalyser.fftSize = 256;
      inputAnalyserRef.current = inputAnalyser;

      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyserRef.current = outputAnalyser;

      // Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const source = inputCtx.createMediaStreamSource(stream);
      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      scriptProcessorRef.current = scriptProcessor;

      source.connect(inputAnalyser); // Connect to visualizer
      inputAnalyser.connect(scriptProcessor);
      scriptProcessor.connect(inputCtx.destination);

      // Initialize Gemini Client
      const ai = new GoogleGenAI({ apiKey });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName } },
          },
          inputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
          outputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
          systemInstruction: "You are a helpful, concise, and friendly AI assistant. Respond naturally to voice."
        },
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Session Opened');
            setIsConnected(true);
          },
          onmessage: async (message: LiveServerMessage) => {
             // Handle Transcriptions
             if (message.serverContent?.outputTranscription) {
                currentOutputTransRef.current += message.serverContent.outputTranscription.text;
             }
             if (message.serverContent?.inputTranscription) {
                const text = message.serverContent.inputTranscription.text;
                currentInputTransRef.current += text;
                setCurrentInput(currentInputTransRef.current);
             }

             if (message.serverContent?.turnComplete) {
                // Commit transcriptions to history
                const userText = currentInputTransRef.current.trim();
                const modelText = currentOutputTransRef.current.trim();

                if (userText) {
                  setMessages(prev => [...prev, {
                    id: Date.now().toString() + '-user',
                    role: 'user',
                    text: userText,
                    timestamp: new Date()
                  }]);
                }

                if (modelText) {
                   setMessages(prev => [...prev, {
                    id: Date.now().toString() + '-model',
                    role: 'model',
                    text: modelText,
                    timestamp: new Date()
                  }]);
                }

                currentInputTransRef.current = '';
                currentOutputTransRef.current = '';
                setCurrentInput('');
             }

             // Handle Audio Output
             const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
             if (base64Audio && outputContextRef.current) {
               const ctx = outputContextRef.current;
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

               const audioBytes = base64ToUint8Array(base64Audio);
               const audioBuffer = await decodeAudioData(audioBytes, ctx);

               const source = ctx.createBufferSource();
               source.buffer = audioBuffer;

               // Connect to visualizer then to destination
               if (outputAnalyserRef.current) {
                 source.connect(outputAnalyserRef.current);
                 outputAnalyserRef.current.connect(ctx.destination);
               } else {
                 source.connect(ctx.destination);
               }

               source.addEventListener('ended', () => {
                 audioSourcesRef.current.delete(source);
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               audioSourcesRef.current.add(source);
             }

             // Handle Interruptions
             if (message.serverContent?.interrupted) {
               console.log('Interrupted');
               audioSourcesRef.current.forEach(src => {
                 try { src.stop(); } catch(e) {} 
               });
               audioSourcesRef.current.clear();
               nextStartTimeRef.current = 0;
               currentOutputTransRef.current = ''; // Clear pending output text on interrupt
             }
          },
          onclose: () => {
            console.log('Session Closed');
            setIsConnected(false);
          },
          onerror: (err) => {
            console.error("Gemini Error:", err);
            setError("Connection error detected.");
            setIsConnected(false);
          }
        }
      });

      // Start processing microphone audio
      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        const pcmBlob = createPcmBlob(inputData);

        // Send to Gemini
        sessionPromise.then(session => {
          session.sendRealtimeInput({ media: pcmBlob });
        });
      };

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to connect to microphone or API.");
      setIsConnected(false);
    }
  }, [voiceName]);

  const disconnect = useCallback(() => {
    // 1. Stop Microphone
    mediaStreamRef.current?.getTracks().forEach(track => track.stop());
    mediaStreamRef.current = null;

    // 2. Stop Processor
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }

    // 3. Close Contexts
    inputContextRef.current?.close();
    outputContextRef.current?.close();
    inputContextRef.current = null;
    outputContextRef.current = null;

    // 4. Reset state
    setIsConnected(false);
    setCurrentInput('');
    // Note: We can't strictly 'close' the session object from here easily without storing the sessionPromise result, 
    // but stopping the audio stream effectively ends the interaction flow.
    // Ideally, we would call session.close() if we stored the session object.
    // For this implementation, closing the audio context and tracks is sufficient to stop usage.
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  return {
    connect,
    disconnect,
    isConnected,
    messages,
    currentInput,
    inputAnalyser: inputAnalyserRef.current,
    outputAnalyser: outputAnalyserRef.current,
    error
  };
};

