          outputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-12-2025" },
          systemInstruction: "You are a helpful and friendly AI assistant. You have access to real-time stock prices from SSI. If a user asks for a stock price, use the getStockPrice tool.",
          tools: [{ functionDeclarations: [stockTool] }],
