const CONSUMER_ID = '78ef642afbfe4835b6661b724498e5d5';
const CONSUMER_SECRET = '17fbdaf8008e4044948550a6991d24cf';

// API Endpoints based on SSI FastConnect Data Spec V2.1
const BASE_URL = 'https://fc-data.ssi.com.vn/api/v2/Market';

let cachedToken: string | null = null;

interface StockData {
  Symbol: string;
  Market: string;
  LastPrice: number;
  Change: number;
  TotalVol: number;
  [key: string]: any;
}

/**
 * Authenticates with SSI API to get an Access Token.
 */
async function authenticate(): Promise<string> {
  try {
    const response = await fetch(`${BASE_URL}/AccessToken`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        consumerID: CONSUMER_ID,
        consumerSecret: CONSUMER_SECRET,
      }),
    });

    if (!response.ok) {
      throw new Error(`Auth failed with status: ${response.status}`);
    }

    const json = await response.json();

    // According to spec example, token might be in json.token or json.data.accessToken
    const token = json.data?.accessToken || json.token;

    if (!token) {
      throw new Error('No access token found in response');
    }

    cachedToken = token;
    return token;
  } catch (error) {
    console.error('SSI Auth Error:', error);
    throw error;
  }
}

/**
 * Checks if the SSI API connection is valid.
 */
export async function checkSSIConnection(): Promise<boolean> {
  try {
    await authenticate();
    return true;
  } catch (error) {
    console.error("SSI Connection Check Failed:", error);
    return false;
  }
}

/**
 * Fetches stock details for a given symbol.
 */
export async function getStockPrice(symbol: string): Promise<any> {
  try {
    // Ensure we have a token
    if (!cachedToken) {
      await authenticate();
    }

    const fetchWithToken = async (token: string) => {
      // Using SecuritiesDetails endpoint (Spec 4.3)
      // Note: Using query params as implied by GET method and field names 'lookupRequest.symbol'
      const url = `${BASE_URL}/SecuritiesDetails?lookupRequest.symbol=${symbol}&lookupRequest.pageIndex=1&lookupRequest.pageSize=1`;

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });

      return response;
    };

    let response = await fetchWithToken(cachedToken!);

    // If unauthorized (401), retry once with new token
    if (response.status === 401) {
      console.log('Token expired, refreshing...');
      const newToken = await authenticate();
      response = await fetchWithToken(newToken);
    }

    if (!response.ok) {
       return { error: `API request failed: ${response.statusText}` };
    }

    const data = await response.json();

    if (data.data && Array.isArray(data.data) && data.data.length > 0) {
      return data.data[0];
    } else {
      return { message: "Stock symbol not found or no data available." };
    }

  } catch (error: any) {
    return { error: error.message || "Internal error fetching stock data" };
  }
}

