                  <button 
                    type="submit"
                    disabled={!isConnected || !inputText.trim()}
                    className="p-3 bg-slate-700 text-blue-400 rounded-full hover:bg-slate-600 hover:text-blue-300 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                  >
                    <Send className="w-5 h-5" />
                  </button>
               </form>
           </div>

           <div className="flex justify-between items-center px-2">
               <div className="text-xs text-slate-500 font-mono">
                  Status: {isConnected ? <span className="text-green-400">Live Connection Active</span> : "Disconnected"}
               </div>
               {isConnected && (
                 <div className="flex items-center gap-2 text-xs text-blue-400 animate-pulse">
                    <Radio className="w-3 h-3" />
                    Listening
                 </div>
               )}
           </div>
        </div>
      </main>

      <footer className="mt-8 text-slate-500 text-sm">
         Powered by Gemini Multimodal Live API
      </footer>
    </div>
  );
};

export default App;
